// Event `which` (0..cnt-1) for a species; nullptr if none/out of range.
static inline const char *daycareSpeciesEvent(uint16_t dex, uint8_t which) {
    if (dex < 1 || dex > 386) return nullptr;
    const DaycareEventSpan &s = kDaycareEventSpan[dex];
    if (s.cnt == 0 || which >= s.cnt) return nullptr;
    return kDaycareEventPool[s.off + which];
}
static inline uint8_t daycareSpeciesEventCount(uint16_t dex) {
    return (dex >= 1 && dex <= 386) ? kDaycareEventSpan[dex].cnt : 0;
}
